"use client";

import { useEffect, useState } from "react";
import { Vendor } from "@/types";
import { getVendors, addVendor } from "@/lib/vendors";
import { useModal } from "@/context/ModalContext";

import VendorDetailModal from "@/components/vendors/VendorDetailModal";

export default function VendorsPage() {
    const { showAlert, showError } = useModal();
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [loading, setLoading] = useState(true);
    const [isFormOpen, setIsFormOpen] = useState(false);

    // Detailed View State
    const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);

    // Form State
    const [formData, setFormData] = useState({
        name: "",
        contactName: "",
        email: "",
        phone: "",
        address: "",
        taxId: "",
        category: "General",
    });

    const fetchVendors = async () => {
        setLoading(true);
        const data = await getVendors();
        setVendors(data.sort((a, b) => a.name.localeCompare(b.name)));
        setLoading(false);
    };

    useEffect(() => {
        fetchVendors();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await addVendor({
                ...formData,
                status: 'ACTIVE'
            });
            setIsFormOpen(false);
            setFormData({ name: "", contactName: "", email: "", phone: "", address: "", taxId: "", category: "General" });
            await showAlert("Success", "Vendor added successfully.");
            fetchVendors(); // Refresh list
        } catch (error: any) {
            console.error("Full error:", error);
            await showError("Error", `Error adding vendor: ${error.message || "Unknown error"}`);
        }
    };

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>Vendors</h1>
                    <p style={{ color: 'var(--text-secondary)' }}>Manage your supplier relationships and performance.</p>
                </div>
                <button className="btn btn-primary" onClick={() => setIsFormOpen(true)}>
                    + Add Vendor
                </button>
            </div>

            {loading ? (
                <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)' }}>Loading vendors...</div>
            ) : vendors.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No vendors found. Add your first vendor to get started.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Company</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Contact Person</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Email</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Status</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {vendors.map((vendor) => (
                                <tr
                                    key={vendor.id}
                                    onClick={() => setSelectedVendor(vendor)}
                                    style={{
                                        borderBottom: '1px solid var(--border)',
                                        cursor: 'pointer',
                                        transition: 'background-color 0.2s',
                                    }}
                                    onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f9fafb'}
                                    onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                                >
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>{vendor.name}</td>
                                    <td style={{ padding: '1rem' }}>{vendor.contactName}</td>
                                    <td style={{ padding: '1rem' }}>{vendor.email}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '999px',
                                            fontSize: '0.75rem',
                                            backgroundColor: vendor.status === 'ACTIVE' ? '#dcfce7' : '#fee2e2',
                                            color: vendor.status === 'ACTIVE' ? '#166534' : '#991b1b',
                                            border: `1px solid ${vendor.status === 'ACTIVE' ? '#bbf7d0' : '#fecaca'}`
                                        }}>
                                            {vendor.status}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1rem' }}>
                                        <button
                                            className="btn-text"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setSelectedVendor(vendor);
                                            }}
                                            style={{ fontSize: '0.875rem', color: 'var(--primary)' }}
                                        >
                                            View Profile
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Vendor Detail Modal */}
            {selectedVendor && (
                <VendorDetailModal
                    vendor={selectedVendor}
                    onClose={() => setSelectedVendor(null)}
                    onEdit={(v) => {
                        // Pre-fill form (Simplified for now, actually just re-opens add form populated)
                        setFormData({
                            name: v.name, contactName: v.contactName, email: v.email,
                            phone: v.phone || "", address: v.address || "", taxId: v.taxId || "",
                            category: v.category || "General"
                        });
                        setSelectedVendor(null);
                        setIsFormOpen(true);
                    }}
                />
            )}

            {/* Add/Edit Modal */}
            {isFormOpen && (
                <div style={{
                    position: 'fixed', inset: 0,
                    backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'flex-start',
                    zIndex: 110, overflowY: 'auto', padding: '2rem 1rem'
                }}>
                    <div className="card" style={{ width: '500px', maxWidth: '90%', marginBottom: '2rem' }}>
                        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>{formData.name ? 'Edit Vendor' : 'Add New Vendor'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div style={{ display: 'grid', gap: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Company Name *</label>
                                    <input required type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Contact Name *</label>
                                    <input required type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.contactName} onChange={e => setFormData({ ...formData, contactName: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Email *</label>
                                    <input required type="email" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Phone</label>
                                    <input type="tel" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Address</label>
                                    <input type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.address} onChange={e => setFormData({ ...formData, address: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Tax ID</label>
                                    <input type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.taxId} onChange={e => setFormData({ ...formData, taxId: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Category *</label>
                                    <select required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)', backgroundColor: 'white' }}
                                        value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                                        <option value="General">General</option>
                                        <option value="IT Services">IT Services</option>
                                        <option value="Office Supplies">Office Supplies</option>
                                        <option value="Logistics">Logistics</option>
                                        <option value="Marketing">Marketing</option>
                                        <option value="Other">Other</option>
                                    </select>
                                </div>
                            </div>
                            <div style={{ marginTop: '2rem', display: 'flex', justifyContent: 'flex-end', gap: '0.5rem' }}>
                                <button type="button" className="btn" style={{ border: '1px solid var(--border)' }} onClick={() => setIsFormOpen(false)}>Cancel</button>
                                <button type="submit" className="btn btn-primary">Save Vendor</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
