"use client";

import { useMemo } from "react";
import { Vendor } from "@/types";

interface VendorDetailModalProps {
    vendor: Vendor;
    onClose: () => void;
    onEdit: (vendor: Vendor) => void;
}

export default function VendorDetailModal({
    vendor,
    onClose,
    onEdit
}: VendorDetailModalProps) {

    // Simulated Scorecard (To be replaced with real analytics later)
    // For now, we generate consistent "random" stats based on the vendor ID string length
    const stats = useMemo(() => {
        const seed = vendor.id ? vendor.id.length : 10;
        return {
            onTimeDelivery: 85 + (seed % 15), // 85-99%
            qualityRating: 4 + (seed % 10) / 10, // 4.0 - 4.9
            totalOrders: seed * 12,
            activeSince: new Date().getFullYear() - (seed % 5)
        };
    }, [vendor.id]);

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 100,
            backgroundColor: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(5px)',
            display: 'flex', alignItems: 'flex-start', justifyContent: 'center', padding: '2rem 1rem',
            overflowY: 'auto'
        }}>
            <div className="card" style={{
                width: '800px', maxWidth: '95%', position: 'relative', padding: 0, border: 'none', marginBottom: '2rem'
            }}>

                {/* Header Banner */}
                <div style={{
                    backgroundColor: 'var(--primary)', color: 'white', padding: '2rem',
                    display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start'
                }}>
                    <div>
                        <div style={{ fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '1px', opacity: 0.8, marginBottom: '0.5rem' }}>Vendor Profile</div>
                        <h2 style={{ fontSize: '2rem', fontWeight: 700, margin: 0 }}>{vendor.name}</h2>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem' }}>
                            <span style={{
                                padding: '0.25rem 0.75rem', borderRadius: '999px', fontSize: '0.8rem', fontWeight: 600,
                                backgroundColor: vendor.status === 'ACTIVE' ? 'rgba(74, 222, 128, 0.2)' : 'rgba(248, 113, 113, 0.2)',
                                color: vendor.status === 'ACTIVE' ? '#dcfce7' : '#fee2e2', border: '1px solid rgba(255,255,255,0.2)'
                            }}>
                                {vendor.status}
                            </span>
                            {vendor.taxId && (
                                <span style={{ padding: '0.25rem 0.75rem', borderRadius: '4px', fontSize: '0.8rem', backgroundColor: 'rgba(255,255,255,0.1)' }}>
                                    Tax ID: {vendor.taxId}
                                </span>
                            )}
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        style={{ background: 'none', border: 'none', color: 'white', fontSize: '1.5rem', cursor: 'pointer', opacity: 0.8 }}
                        title="Close"
                    >
                        &times;
                    </button>
                </div>

                <div style={{ padding: '2rem', display: 'grid', gridTemplateColumns: '1fr 300px', gap: '2rem' }}>

                    {/* Left Column: Contact & Details */}
                    <div>
                        <h3 style={{ borderBottom: '1px solid var(--border)', paddingBottom: '0.5rem', marginBottom: '1.5rem', fontSize: '1.1rem', color: 'var(--primary)' }}>Contact Information</h3>

                        <div style={{ display: 'grid', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                <div style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem' }}>👤</div>
                                <div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Contact Person</div>
                                    <div style={{ fontWeight: 600 }}>{vendor.contactName}</div>
                                </div>
                            </div>

                            <a href={`mailto:${vendor.email}`} style={{ display: 'flex', gap: '1rem', alignItems: 'center', textDecoration: 'none', color: 'inherit' }}>
                                <div style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#e0f2fe', color: '#0284c7', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem' }}>✉️</div>
                                <div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Email Address</div>
                                    <div style={{ fontWeight: 600, color: 'var(--primary)' }}>{vendor.email}</div>
                                </div>
                            </a>

                            <a href={`tel:${vendor.phone}`} style={{ display: 'flex', gap: '1rem', alignItems: 'center', textDecoration: 'none', color: 'inherit' }}>
                                <div style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#dcfce7', color: '#16a34a', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem' }}>📞</div>
                                <div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Phone Number</div>
                                    <div style={{ fontWeight: 600 }}>{vendor.phone || 'N/A'}</div>
                                </div>
                            </a>

                            <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                <div style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#fdf4ff', color: '#d946ef', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem' }}>🏢</div>
                                <div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Address</div>
                                    <div style={{ fontWeight: 500, lineHeight: '1.4' }}>{vendor.address || 'No address provided'}</div>
                                </div>
                            </div>
                        </div>

                        <div style={{ marginTop: '2.5rem' }}>
                            <button
                                onClick={() => onEdit(vendor)}
                                className="btn"
                                style={{ width: '100%', border: '1px solid var(--border)', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                            >
                                ✏️ Edit Vendor Details
                            </button>
                        </div>
                    </div>

                    {/* Right Column: Scorecard & Metrics */}
                    <div style={{ backgroundColor: '#f8fafc', padding: '1.5rem', borderRadius: '12px', border: '1px solid #e2e8f0' }}>
                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            🏆 Vendor Scorecard
                        </h3>

                        <div style={{ marginBottom: '1.5rem' }}>
                            <div style={{ fontSize: '0.8rem', color: '#64748b', marginBottom: '0.25rem' }}>Performance Rating</div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <span style={{ fontSize: '2rem', fontWeight: 'bold', color: '#f59e0b' }}>{stats.qualityRating}</span>
                                <div style={{ display: 'flex', color: '#f59e0b' }}>
                                    {[...Array(5)].map((_, i) => (
                                        <span key={i} style={{ opacity: i < Math.round(stats.qualityRating) ? 1 : 0.3 }}>★</span>
                                    ))}
                                </div>
                            </div>
                            <div style={{ fontSize: '0.75rem', color: '#94a3b8' }}>Based on recent feedback</div>
                        </div>

                        <div style={{ marginBottom: '1.5rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                <span style={{ fontSize: '0.8rem', color: '#64748b' }}>On-Time Delivery</span>
                                <span style={{ fontSize: '0.8rem', fontWeight: 600 }}>{stats.onTimeDelivery}%</span>
                            </div>
                            <div style={{ width: '100%', height: '6px', backgroundColor: '#e2e8f0', borderRadius: '99px' }}>
                                <div style={{ width: `${stats.onTimeDelivery}%`, height: '100%', backgroundColor: stats.onTimeDelivery > 90 ? '#22c55e' : '#f59e0b', borderRadius: '99px' }}></div>
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', paddingTop: '1.5rem', borderTop: '1px solid #e2e8f0' }}>
                            <div>
                                <div style={{ fontSize: '1.25rem', fontWeight: 'bold' }}>{stats.totalOrders}</div>
                                <div style={{ fontSize: '0.75rem', color: '#64748b' }}>Lifetime Orders</div>
                            </div>
                            <div>
                                <div style={{ fontSize: '1.25rem', fontWeight: 'bold' }}>{stats.activeSince}</div>
                                <div style={{ fontSize: '0.75rem', color: '#64748b' }}>Partner Since</div>
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}
